<?php
 namespace League\CommonMark\Util; final class Configuration implements ConfigurationInterface { private $config; public function __construct(array $config = []) { $this->config = $config; } public function merge(array $config = []) { $this->config = \array_replace_recursive($this->config, $config); } public function replace(array $config = []) { $this->config = $config; } public function get(?string $key = null, $default = null) { if ($key === null) { @\trigger_error('Calling Configuration::get() without a $key is deprecated in league/commonmark 1.6 and will not be allowed in 2.0', \E_USER_DEPRECATED); return $this->config; } if (\strpos($key, '/')) { return $this->getConfigByPath($key, $default); } if (!isset($this->config[$key])) { return $default; } return $this->config[$key]; } public function set(string $key, $value = null) { if (\func_num_args() === 1) { @\trigger_error('Calling Configuration::set() without a $value is deprecated in league/commonmark 1.6 and will not be allowed in 2.0', \E_USER_DEPRECATED); } if (\strpos($key, '/')) { $this->setByPath($key, $value); } $this->config[$key] = $value; } public function exists(string $key): bool { return $this->getConfigByPath($key, self::MISSING) !== self::MISSING; } private function getConfigByPath(string $keyPath, $default = null) { $keyArr = \explode('/', $keyPath); $data = $this->config; foreach ($keyArr as $k) { if (!\is_array($data) || !isset($data[$k])) { return $default; } $data = $data[$k]; } return $data; } private function setByPath(string $keyPath, $value = null): void { $keyArr = \explode('/', $keyPath); $pointer = &$this->config; while (($k = \array_shift($keyArr)) !== null) { if (!\is_array($pointer)) { $pointer = []; } if (!isset($pointer[$k])) { $pointer[$k] = null; } $pointer = &$pointer[$k]; } $pointer = $value; } } 